export default function Hero({title, subtitle, cta}){
  return (
    <section className="hero-full">
      <div className="container">
        <div className="md:pt-12 lg:pt-24">
          <div className="md:w-7/12 lg:w-6/12">
            <h1 className="heading-display text-5xl md:text-7xl font-extrabold mb-6">{title}</h1>
            <p className="text-lg md:text-xl muted mb-8">{subtitle}</p>
            {cta && <a href={cta.href} className="inline-block px-6 py-3 bg-brand text-white tracking-wide">{cta.label}</a>}
          </div>
        </div>
      </div>
    </section>
  )
}
